// NewNfcCardEmulationStub creates a server-side INfcCardEmulation wrapping the given
// server implementation. The returned value satisfies INfcCardEmulation
// and can be passed to proxy methods; its AsBinder() returns a
// *binder.StubBinder that is auto-registered with the binder
// driver on first use.
func NewNfcCardEmulationStub(
	impl INfcCardEmulationServer,
) INfcCardEmulation {
	wrapper := &nfcCardEmulationStubWrapper{impl: impl}
	stub := &NfcCardEmulationStub{Impl: wrapper}
	wrapper.stubBinder = binder.NewStubBinder(stub)
	return wrapper
}
